def fetch_json_sync(url: str) -> Any:
    req_url = url if url.startswith("http") else f"{BASE_URL}/{url.lstrip('/')}"
    with urlopen(req_url, timeout=40) as response:
        return json.loads(response.read().decode("utf-8"))


async def fetch_json(url: str) -> Any:
    return await asyncio.to_thread(fetch_json_sync, url)


def fetch_raw_sync(path: str) -> Any:
    req_url = f"{RAW_BASE}/{path.lstrip('/')}"
    with urlopen(req_url, timeout=40) as response:
        return json.loads(response.read().decode("utf-8"))


async def fetch_raw(path: str) -> Any:
    return await asyncio.to_thread(fetch_raw_sync, path)


async def fetch_endpoint(url: str) -> Any:
    """Try live API first; fall back to static api-data mirror."""
    try:
        return await fetch_json(url)
    except (URLError, HTTPError, TimeoutError):
        mapped = map_to_static_path(url)
        if mapped is None:
            raise
        return await fetch_raw(mapped)


def map_to_static_path(url: str) -> Optional[str]:
    clean = url.strip("/")
    if clean.startswith("pokemon/") and clean.endswith("/encounters"):
        poke_id = clean.split("/")[1]
        return f"pokemon/{poke_id}/encounters/index.json"
    if clean.startswith("pokemon/"):
        poke_id = clean.split("/")[1]
        return f"pokemon/{poke_id}/index.json"
    if clean.startswith("pokemon-species/"):
        species_id = clean.split("/")[1]
        return f"pokemon-species/{species_id}/index.json"
    if clean.startswith("evolution-chain/"):
        chain_id = clean.split("/")[1]
        return f"evolution-chain/{chain_id}/index.json"
    return None


def slug_to_text(value: str) -> str:
    return value.replace("-", " ")


def parse_generation(species: Dict[str, Any]) -> int:
    name = species["generation"]["name"]
    roman = name.replace("generation-", "")
    roman_map = {"i": 1, "ii": 2, "iii": 3, "iv": 4, "v": 5, "vi": 6, "vii": 7, "viii": 8, "ix": 9}
    return roman_map.get(roman, 0)


def parse_evolution_id(url: str) -> int:
    match = re.search(r"/evolution-chain/(\d+)/", url)
    if not match:
        raise ValueError(f"Unable to parse evolution chain id from {url}")
    return int(match.group(1))


def extract_condition(detail: Dict[str, Any]) -> str:
    trigger = detail.get("trigger", {}).get("name")
    if detail.get("min_level") is not None:
        return f"level {detail['min_level']}"

    parts: List[str] = []
    if detail.get("item"):
        parts.append(f"use {slug_to_text(detail['item']['name'])}")
    if detail.get("held_item"):
        parts.append(f"holding {slug_to_text(detail['held_item']['name'])}")
    if detail.get("known_move"):
        parts.append(f"knows {slug_to_text(detail['known_move']['name'])}")
    if detail.get("known_move_type"):
        parts.append(f"knows a {slug_to_text(detail['known_move_type']['name'])} type move")
    if detail.get("location"):
        parts.append(f"at {slug_to_text(detail['location']['name'])}")
    if detail.get("min_happiness"):
        parts.append("high friendship")
    if detail.get("min_beauty"):
        parts.append("high beauty")
    if detail.get("min_affection"):
        parts.append("high affection")
    if detail.get("gender") == 1:
        parts.append("female")
    elif detail.get("gender") == 2:
        parts.append("male")
    if detail.get("time_of_day"):
        parts.append(detail["time_of_day"])
    if detail.get("needs_overworld_rain"):
        parts.append("during rain")
    if detail.get("turn_upside_down"):
        parts.append("hold device upside down")
    if detail.get("party_species"):
        parts.append(f"with {slug_to_text(detail['party_species']['name'])} in party")
    if detail.get("party_type"):
        parts.append(f"with {slug_to_text(detail['party_type']['name'])} type in party")

    rel = detail.get("relative_physical_stats")
    if rel == 1:
        parts.append("attack > defense")
    elif rel == -1:
        parts.append("attack < defense")
    elif rel == 0:
        parts.append("attack = defense")

    if detail.get("trade_species"):
        parts.append(f"trade for {slug_to_text(detail['trade_species']['name'])}")

    if not parts and trigger == "trade":
        parts.append("trade")
    if not parts and trigger == "level-up":
        parts.append("level up")
    if not parts and trigger == "use-item":
        parts.append("use evolution item")
    if not parts and trigger:
        parts.append(slug_to_text(trigger))

    return ", ".join(parts) if parts else "special condition"


def flatten_chain(node: Dict[str, Any], stage: int, flat: List[str]) -> None:
    flat.append(node["species"]["name"])
    for child in node.get("evolves_to", []):
        flatten_chain(child, stage + 1, flat)


def build_evolution_payload(target_name: str, evolution_chain: Dict[str, Any]) -> Dict[str, Any]:
    root = evolution_chain["chain"]
    chain_names: List[str] = []
    flatten_chain(root, 1, chain_names)

    from_payload: Optional[Dict[str, str]] = None
    to_payload: Optional[Dict[str, str]] = None
    stage = 1

    def visit(node: Dict[str, Any], depth: int, parent_name: Optional[str], parent_condition: Optional[str]) -> bool:
        nonlocal from_payload, to_payload, stage
        name = node["species"]["name"]
        if name == target_name:
            stage = depth
            if parent_name:
                from_payload = {"name": parent_name, "condition": parent_condition or "special condition"}
            if node.get("evolves_to"):
                child = node["evolves_to"][0]
                details = child.get("evolution_details") or [{}]
                to_payload = {"name": child["species"]["name"], "condition": extract_condition(details[0])}
            return True

        for child in node.get("evolves_to", []):
            details = child.get("evolution_details") or [{}]
            condition = extract_condition(details[0])
            if visit(child, depth + 1, name, condition):
                return True
        return False

    visit(root, 1, None, None)

    return {
        "chain": chain_names,
        "stage": stage,
        "from": from_payload,
        "to": to_payload,
    }


def build_learnset(pokemon: Dict[str, Any]) -> List[Dict[str, str]]:
    unique_by_move: Dict[str, int] = {}
    for move_entry in pokemon.get("moves", []):
        move_name = slug_to_text(move_entry["move"]["name"])
        levels = [
            detail.get("level_learned_at", 0)
            for detail in move_entry.get("version_group_details", [])
            if detail.get("move_learn_method", {}).get("name") == "level-up"
        ]
        if not levels:
            continue
        level = min(levels)
        if move_name not in unique_by_move or level < unique_by_move[move_name]:
            unique_by_move[move_name] = level

    ordered: List[Tuple[int, str]] = sorted((level, move) for move, level in unique_by_move.items())
    return [{"move": move, "method": f"level {level}"} for level, move in ordered[:5]]


def format_locations(encounters: List[Dict[str, Any]]) -> List[str]:
    locations: List[str] = []
    for encounter in encounters[:3]:
        name = slug_to_text(encounter.get("location_area", {}).get("name", "")).strip()
        if name and name not in locations:
            locations.append(name)
    return locations or ["not found in the wild"]


async def build_one(poke_id: int, evolution_cache: Dict[int, Dict[str, Any]], evolution_lock: asyncio.Lock) -> Dict[str, Any]:
    pokemon, species, encounters = await asyncio.gather(
        fetch_endpoint(f"pokemon/{poke_id}"),
        fetch_endpoint(f"pokemon-species/{poke_id}"),
        fetch_endpoint(f"pokemon/{poke_id}/encounters"),
    )

    evo_id = parse_evolution_id(species["evolution_chain"]["url"])
    async with evolution_lock:
        if evo_id not in evolution_cache:
            evolution_cache[evo_id] = await fetch_endpoint(f"evolution-chain/{evo_id}")
    evolution = build_evolution_payload(pokemon["name"], evolution_cache[evo_id])

    cry = pokemon.get("cries", {}).get("latest") or f"https://raw.githubusercontent.com/PokeAPI/cries/main/cries/pokemon/latest/{poke_id}.ogg"

    return {
        "id": poke_id,
        "name": pokemon["name"],
        "types": [entry["type"]["name"] for entry in sorted(pokemon["types"], key=lambda x: x["slot"])],
        "generation": parse_generation(species),
        "cry_url": cry,
        "learnset": build_learnset(pokemon),
        "evolution": evolution,
        "locations": format_locations(encounters),
    }


async def build_dataset(limit: int) -> List[Dict[str, Any]]:
    evolution_cache: Dict[int, Dict[str, Any]] = {}
    evolution_lock = asyncio.Lock()
    results: List[Dict[str, Any]] = []

    for start in range(1, limit + 1, BATCH_SIZE):
        end = min(start + BATCH_SIZE - 1, limit)
        print(f"Fetching {start}-{end} / {limit}...")
        tasks = [build_one(pid, evolution_cache, evolution_lock) for pid in range(start, end + 1)]
        batch = await asyncio.gather(*tasks)
        results.extend(batch)
        await asyncio.sleep(BATCH_DELAY_SECONDS)

    results.sort(key=lambda p: p["id"])
    return results


def save_data(data: List[Dict[str, Any]]) -> None:
    OUT_PATH.write_text(json.dumps(data, separators=(",", ":")), encoding="utf-8")
    print(f"Saved {len(data)} pokemon to {OUT_PATH}")


def load_fallback_gen1() -> List[Dict[str, Any]]:
    return json.loads(FALLBACK_GEN1_JSON)


async def main() -> int:
    parser = argparse.ArgumentParser(description="Build squirtle/pokemon_data.json from PokeAPI")
    parser.add_argument("--limit", type=int, help="Max pokemon to fetch (default: all available)")
    parser.add_argument(
        "--use-fallback-gen1",
        action="store_true",
        help="Write embedded Gen 1 fallback dataset without network",
    )
    args = parser.parse_args()

    if args.use_fallback_gen1:
        fallback = load_fallback_gen1()
        if not fallback:
            print("Fallback dataset is empty. Generate once with --limit 151 and embed it.", file=sys.stderr)
            return 1
        save_data(fallback)
        return 0

    limit = max(1, args.limit if args.limit else DEFAULT_LIMIT)
    started = time.time()
    try:
        dataset = await build_dataset(limit)
    except (HTTPError, URLError, TimeoutError) as exc:
        print(f"Build failed: {exc}", file=sys.stderr)
        if limit >= 151:
            fallback = load_fallback_gen1()
            if fallback:
                print("Using embedded Gen 1 fallback dataset.")
                save_data(fallback)
                return 0
        return 1

    save_data(dataset)
    print(f"Done in {time.time() - started:.1f}s")
    return 0


if __name__ == "__main__":
    raise SystemExit(asyncio.run(main()))
